      office: { title: 'Класичний офіс', desc: 'Чиста продуктивність без відволікань. Чіткі лінії, акустичні панелі на всю висоту, регульовані столи та стримана професійна палітра. Кожна поверхня створена для функції — інтегроване управління кабелями та точне освітлення.', features: ['Регульовані столи sit/stand','Акустичні панелі на всю висоту','Інтегроване управління кабелями','Стіни-дошки для нотаток','Точне робоче освітлення'] },
      bar: { title: 'Коктейль-бар', desc: 'Творча енергія зустрічає шарм спікізі. Настрійне підвісне освітлення, латунні елементи, оксамитові сидіння та вбудований еспресо-бар створюють сцену для сміливих ідей. Темний горіх та амбієнтний джаз.', features: ['Вбудований еспресо-бар','Настрійне підвісне освітлення','Палітра латуні та оксамиту','Робочі поверхні з темного горіха','Амбієнтна музична система'] },
      library: { title: 'Бібліотека', desc: 'Вчений притулок на рейках. Книжкові полиці від підлоги до стелі (з кураторською добіркою), шкіряні крісла запрошують до глибоких роздумів, а латунні лампи створюють теплі острівці світла. Тиша за дизайном.', features: ['Полиці від підлоги до стелі','Кураторська колекція книг','Шкіряні крісла та куточки для читання','Латунні лампи для читання','Шумопоглинаючий килим та штори'] },
      scandi: { title: 'Скандинавський мінімалізм', desc: 'Хюґе зустрічає функцію. Березова фанера, вовняні пледи, приглушені земляні тони та чисті скандинавські форми. Стриманий, заспокійливий простір, що прибирає зайве.', features: ['Столи та полиці з березової фанери','Вовняні пледи та м\'який текстиль','Палітра приглушених земляних тонів','Мінімалістичні скандинавські меблі','Тепле непряме освітлення'] },
